#!/bin/bash\n################################################################################\n# VPN Endpoint Validation & Testing Script\n# Purpose: Test VPN connectivity and endpoint health for production access\n# Usage: ./scripts/vpc-vpn-endpoint-validation.sh [--endpoint <IP>] [--verbose]\n# Status: Production-ready validation gate\n################################################################################\n\nset -euo pipefail\n\n# ─── Configuration ────────────────────────────────────────────────────────────\nVPN_GATEWAY_IP=\"${VPN_GATEWAY_IP:-192.168.168.1}\"\nVPN_ENDPOINT_PORT=\"${VPN_ENDPOINT_PORT:-1194}\"\nVPN_PROTOCOL=\"${VPN_PROTOCOL:-udp}\"\nPRODUCTION_HOST=\"${PRODUCTION_HOST:-192.168.168.31}\"\nSTANDBY_HOST=\"${STANDBY_HOST:-192.168.168.42}\"\nNAS_HOST=\"${NAS_HOST:-192.168.168.56}\"\nTESTIMEOUT=5\nVERBOSE=false\n\n# ─── Colors ──────────────────────────────────────────────────────────────────\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nNC='\\033[0m' # No Color\n\n# ─── Logging ──────────────────────────────────────────────────────────────────\nlog() { echo -e \"${GREEN}[VPN-VALIDATOR]${NC} $*\"; }\ninfo() { echo -e \"${BLUE}[INFO]${NC} $*\"; }\nwarn() { echo -e \"${YELLOW}[WARNING]${NC} $*\" >&2; }\nerror() { echo -e \"${RED}[ERROR]${NC} $*\" >&2; }\n\n# ─── Parse arguments ──────────────────────────────────────────────────────────\nwhile [[ $# -gt 0 ]]; do\n  case $1 in\n    --endpoint) VPN_GATEWAY_IP=\"$2\"; shift 2 ;;\n    --port) VPN_ENDPOINT_PORT=\"$2\"; shift 2 ;;\n    --protocol) VPN_PROTOCOL=\"$2\"; shift 2 ;;\n    --verbose) VERBOSE=true; shift ;;\n    *) error \"Unknown option: $1\"; exit 1 ;;\n  esac\ndone\n\n# ─── Main Validation ──────────────────────────────────────────────────────────\n\nlog \"Starting VPN endpoint validation...\"\nlog \"Gateway: $VPN_GATEWAY_IP:$VPN_ENDPOINT_PORT ($VPN_PROTOCOL)\"\ninfo \"\"\n\n# Test 1: Check VPN gateway connectivity\nlog \"[1/6] Testing VPN gateway connectivity...\"\nif timeout $TESTTIMEOUT ping -c 1 \"$VPN_GATEWAY_IP\" &>/dev/null 2>&1; then\n  echo -e \"  ${GREEN}✓${NC} VPN gateway reachable\"\nelse\n  error \"Cannot reach VPN gateway at $VPN_GATEWAY_IP\"\n  exit 1\nfi\n\n# Test 2: Check VPN endpoint port\nlog \"[2/6] Testing VPN endpoint port ($VPN_PROTOCOL:$VPN_ENDPOINT_PORT)...\"\nif timeout $TESTTIMEOUT nc -z -u \"$VPN_GATEWAY_IP\" \"$VPN_ENDPOINT_PORT\" 2>/dev/null || \\\n   timeout $TESTTIMEOUT bash -c \"echo > /dev/udp/$VPN_GATEWAY_IP/$VPN_ENDPOINT_PORT\" 2>/dev/null; then\n  echo -e \"  ${GREEN}✓${NC} VPN endpoint port accessible\"\nelse\n  warn \"Cannot reach VPN endpoint port (may be normal if closed externally)\"\nfi\n\n# Test 3: Check production host via VPN\nlog \"[3/6] Testing production host connectivity ($PRODUCTION_HOST)...\"\nif timeout $TESTTIMEOUT ping -c 1 \"$PRODUCTION_HOST\" &>/dev/null 2>&1; then\n  echo -e \"  ${GREEN}✓${NC} Production host ($PRODUCTION_HOST) reachable\"\nelse\n  error \"Cannot reach production host at $PRODUCTION_HOST\"\n  exit 1\nfi\n\n# Test 4: Check standby host via VPN\nlog \"[4/6] Testing standby host connectivity ($STANDBY_HOST)...\"\nif timeout $TESTTIMEOUT ping -c 1 \"$STANDBY_HOST\" &>/dev/null 2>&1; then\n  echo -e \"  ${GREEN}✓${NC} Standby host ($STANDBY_HOST) reachable\"\nelse\n  warn \"Standby host ($STANDBY_HOST) not reachable (may be powered down)\"\nfi\n\n# Test 5: Check NAS via VPN\nlog \"[5/6] Testing NAS connectivity ($NAS_HOST)...\"\nif timeout $TESTTIMEOUT ping -c 1 \"$NAS_HOST\" &>/dev/null 2>&1; then\n  echo -e \"  ${GREEN}✓${NC} NAS ($NAS_HOST) reachable\"\nelse\n  error \"Cannot reach NAS at $NAS_HOST\"\n  exit 1\nfi\n\n# Test 6: Check SSH to production host\nlog \"[6/6] Testing SSH connectivity to production host...\"\nif timeout $TESTTIMEOUT ssh -o ConnectTimeout=$TESTTIMEOUT -o BatchMode=yes akushnir@\"$PRODUCTION_HOST\" echo \"Connected\" &>/dev/null 2>&1; then\n  echo -e \"  ${GREEN}✓${NC} SSH connection successful (passwordless auth working)\"\nelse\n  warn \"SSH connection failed (may need key setup; NAS/rsync may still work)\"\nfi\n\nlog \"\"\nlog \"✅ VPN Endpoint Validation PASSED\"\nlog \"   All critical endpoints reachable\"\nlog \"   VPN connection ready for production deployment\"\nlog \"\"\n\nexit 0\n"